async function seed() {
  console.log('🌱 Starting AutoVahan database seed...')
  console.log(`📦 Preparing to insert ${carsData.length} cars`)

  try {
    // Clear existing cars (optional - comment out if you want to keep existing)
    console.log('🗑️  Clearing existing cars...')
    const { error: deleteError } = await supabase.from('cars').delete().neq('id', 0)
    if (deleteError) {
      console.warn('Warning during delete (may be empty table):', deleteError.message)
    }

    // Insert all cars
    console.log('📥 Inserting cars...')
    const { data, error } = await supabase.from('cars').insert(carsData)

    if (error) {
      console.error('❌ Error inserting cars:', error)
      process.exit(1)
    }

    console.log(`✅ Successfully seeded ${carsData.length} cars!`)
    console.log('🎉 Database is ready for production use.')

    // Verify count
    const { count } = await supabase.from('cars').select('*', { count: 'exact', head: true })
    console.log(`📊 Total cars in database: ${count}`)

  } catch (err) {
    console.error('💥 Seed failed:', err)
    process.exit(1)
  }
}

seed()
